use strict;
use warnings;

sub square {
    my ($x) = @_;
    return $x * $x;
}

sub add {
    my ($a, $b) = @_;
    return $a + $b;
}

# Varsayilan parametre (manuel kontrol ile)
sub greet {
    my ($name, $greeting) = @_;
    $greeting //= "Merhaba";
    return "$greeting, $name!";
}

# Degisken sayida parametre
sub total {
    my $sum = 0;
    $sum += $_ for @_;
    return $sum;
}

print "Kare: " . square(5) . "\n";
print "Toplam: " . add(3, 7) . "\n";
print greet("Ayse") . "\n";
print greet("Mehmet", "Selam") . "\n";
print "Coklu toplam: " . total(1, 2, 3, 4, 5) . "\n";

# Anonim fonksiyon (referans)
my $multiply = sub {
    my ($a, $b) = @_;
    return $a * $b;
};

print "\nAnonim fonksiyon carpim: " . $multiply->(4, 5) . "\n";
